import os
import sys
import tarfile
import zipfile
import subprocess
import shutil
import tempfile
import datetime
import re
import stat


def validate_path(path):
    """Validate and sanitize the provided path."""
    real_path = os.path.realpath(path)
    
    if not os.path.exists(real_path):
        raise ValueError("Path does not exist: {}".format(real_path))
    
    if not os.path.isdir(real_path):
        raise ValueError("Path is not a directory: {}".format(real_path))
    
    # Prevent backing up sensitive system directories
    sensitive_dirs = ['/etc', '/boot', '/dev', '/proc', '/sys', '/run', '/var/run']
    for sensitive in sensitive_dirs:
        if real_path == os.path.realpath(sensitive):
            raise ValueError("Cannot backup sensitive system directory: {}".format(sensitive))
    
    # Check read permissions
    if not os.access(real_path, os.R_OK):
        raise ValueError("No read permission for: {}".format(real_path))
    
    return real_path


def validate_format(fmt):
    """Validate the compression format."""
    allowed_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    fmt_lower = fmt.lower().strip()
    if fmt_lower not in allowed_formats:
        raise ValueError("Unsupported format '{}'. Allowed: {}".format(fmt, ', '.join(allowed_formats)))
    return fmt_lower


def sanitize_filename(name):
    """Sanitize a filename to prevent path traversal or injection."""
    # Remove any path separators and dangerous characters
    name = os.path.basename(name)
    name = re.sub(r'[^\w\-.]', '_', name)
    if not name or name.startswith('.'):
        name = 'backup'
    return name


def generate_backup_name(source_path, fmt):
    """Generate a safe backup filename with timestamp."""
    dir_name = os.path.basename(source_path)
    if not dir_name:
        dir_name = 'root'
    dir_name = sanitize_filename(dir_name)
    timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
    backup_name = "backup_{}_{}".format(dir_name, timestamp)
    return "{}.{}".format(backup_name, fmt)


def get_output_dir():
    """Get a safe output directory for backups."""
    # Try user's home directory first, then /tmp
    home = os.path.expanduser('~')
    backup_dir = os.path.join(home, 'backups')
    
    try:
        if not os.path.exists(backup_dir):
            os.makedirs(backup_dir, mode=0o700)
        else:
            # Ensure proper permissions on existing directory
            current_mode = os.stat(backup_dir).st_mode
            if current_mode & (stat.S_IRWXG | stat.S_IRWXO):
                os.chmod(backup_dir, 0o700)
        return backup_dir
    except OSError:
        # Fall back to a temp directory
        backup_dir = tempfile.mkdtemp(prefix='backup_')
        os.chmod(backup_dir, 0o700)
        return backup_dir


def check_symlink_safety(base_path, member_path):
    """Check that a tar member doesn't escape the base directory via symlinks."""
    abs_base = os.path.realpath(base_path)
    abs_member = os.path.realpath(os.path.join(base_path, member_path))
    return abs_member.startswith(abs_base + os.sep) or abs_member == abs_base


def create_tar_gz(source_path, output_path):
    """Create a tar.gz archive."""
    try:
        with tarfile.open(output_path, 'w:gz') as tar:
            base_name = os.path.basename(source_path)
            for root, dirs, files in os.walk(source_path, followlinks=False):
                for name in files + dirs:
                    full_path = os.path.join(root, name)
                    # Skip symlinks that point outside the source
                    if os.path.islink(full_path):
                        link_target = os.path.realpath(full_path)
                        source_real = os.path.realpath(source_path)
                        if not (link_target.startswith(source_real + os.sep) or link_target == source_real):
                            print("Skipping symlink escaping source: {}".format(full_path))
                            continue
                    arcname = os.path.join(base_name, os.path.relpath(full_path, source_path))
                    tar.add(full_path, arcname=arcname, recursive=False)
        # Set restrictive permissions on output
        os.chmod(output_path, 0o600)
        return True
    except tarfile.TarError as e:
        print("Error creating tar.gz: {}".format(e))
        return False
    except OSError as e:
        print("OS error creating tar.gz: {}".format(e))
        return False


def create_tar_bz2(source_path, output_path):
    """Create a tar.bz2 archive."""
    try:
        with tarfile.open(output_path, 'w:bz2') as tar:
            base_name = os.path.basename(source_path)
            for root, dirs, files in os.walk(source_path, followlinks=False):
                for name in files + dirs:
                    full_path = os.path.join(root, name)
                    if os.path.islink(full_path):
                        link_target = os.path.realpath(full_path)
                        source_real = os.path.realpath(source_path)
                        if not (link_target.startswith(source_real + os.sep) or link_target == source_real):
                            print("Skipping symlink escaping source: {}".format(full_path))
                            continue
                    arcname = os.path.join(base_name, os.path.relpath(full_path, source_path))
                    tar.add(full_path, arcname=arcname, recursive=False)
        os.chmod(output_path, 0o600)
        return True
    except tarfile.TarError as e:
        print("Error creating tar.bz2: {}".format(e))
        return False
    except OSError as e:
        print("OS error creating tar.bz2: {}".format(e))
        return False


def create_zip(source_path, output_path):
    """Create a zip archive."""
    try:
        with zipfile.ZipFile(output_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
            base_name = os.path.basename(source_path)
            for root, dirs, files in os.walk(source_path, followlinks=False):
                for name in files:
                    full_path = os.path.join(root, name)
                    if os.path.islink(full_path):
                        link_target = os.path.realpath(full_path)
                        source_real = os.path.realpath(source_path)
                        if not (link_target.startswith(source_real + os.sep) or link_target == source_real):
                            print("Skipping symlink escaping source: {}".format(full_path))
                            continue
                    arcname = os.path.join(base_name, os.path.relpath(full_path, source_path))
                    # Validate arcname doesn't contain path traversal
                    if '..' in arcname.split(os.sep):
                        print("Skipping suspicious path: {}".format(arcname))
                        continue
                    zipf.write(full_path, arcname)
        os.chmod(output_path, 0o600)
        return True
    except zipfile.BadZipFile as e:
        print("Error creating zip: {}".format(e))
        return False
    except OSError as e:
        print("OS error creating zip: {}".format(e))
        return False


def create_7z(source_path, output_path):
    """Create a 7z archive using the 7z command-line tool."""
    # Check if 7z is available
    sevenz_path = shutil.which('7z') if hasattr(shutil, 'which') else None
    if sevenz_path is None:
        # Fallback for older Python without shutil.which
        sevenz_path = None
        for path_dir in os.environ.get('PATH', '').split(os.pathsep):
            candidate = os.path.join(path_dir, '7z')
            if os.path.isfile(candidate) and os.access(candidate, os.X_OK):
                sevenz_path = candidate
                break
    
    if sevenz_path is None:
        # Try 7za as alternative
        for path_dir in os.environ.get('PATH', '').split(os.pathsep):
            candidate = os.path.join(path_dir, '7za')
            if os.path.isfile(candidate) and os.access(candidate, os.X_OK):
                sevenz_path = candidate
                break
    
    if sevenz_path is None:
        print("Error: 7z/7za command not found. Please install p7zip.")
        print("On Debian/Ubuntu: sudo apt-get install p7zip-full")
        print("On CentOS/RHEL: sudo yum install p7zip p7zip-plugins")
        return False
    
    try:
        # Use absolute paths and avoid shell=True to prevent injection
        cmd = [sevenz_path, 'a', '-t7z', '-mx=5', output_path, source_path]
        
        process = subprocess.Popen(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env={'PATH': os.environ.get('PATH', '')},  # Minimal environment
        )
        stdout, stderr = process.communicate(timeout=3600)  # 1 hour timeout
        
        if process.returncode != 0:
            print("7z error (exit code {}):".format(process.returncode))
            if stderr:
                # Decode safely
                try:
                    print(stderr.decode('utf-8', errors='replace'))
                except Exception:
                    print("(could not decode error output)")
            return False
        
        os.chmod(output_path, 0o600)
        return True
    except subprocess.TimeoutExpired:
        process.kill()
        print("Error: 7z process timed out after 1 hour")
        # Clean up partial file
        if os.path.exists(output_path):
            os.unlink(output_path)
        return False
    except OSError as e:
        print("Error running 7z: {}".format(e))
        return False
    except Exception as e:
        print("Unexpected error running 7z: {}".format(e))
        return False


def get_dir_size(path):
    """Calculate total size of directory in bytes."""
    total = 0
    try:
        for root, dirs, files in os.walk(path, followlinks=False):
            for f in files:
                fp = os.path.join(root, f)
                if not os.path.islink(fp):
                    try:
                        total += os.path.getsize(fp)
                    except OSError:
                        pass
    except OSError:
        pass
    return total


def format_size(size_bytes):
    """Format bytes into human-readable size."""
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size_bytes < 1024.0:
            return "{:.2f} {}".format(size_bytes, unit)
        size_bytes /= 1024.0
    return "{:.2f} PB".format(size_bytes)


def main():
    # Parse arguments
    if len(sys.argv) < 3:
        print("Usage: {} <directory_path> <format>".format(sys.argv[0]))
        print("Supported formats: tar.gz, tar.bz2, zip, 7z")
        print("")
        print("Example:")
        print("  {} /home/user tar.gz".format(sys.argv[0]))
        print("  {} /home/user zip".format(sys.argv[0]))
        sys.exit(1)
    
    source_path_arg = sys.argv[1]
    format_arg = sys.argv[2]
    
    # Validate inputs
    try:
        source_path = validate_path(source_path_arg)
        compression_format = validate_format(format_arg)
    except ValueError as e:
        print("Validation error: {}".format(e))
        sys.exit(1)
    
    # Check available disk space (basic check)
    source_size = get_dir_size(source_path)
    print("Source directory: {}".format(source_path))
    print("Source size: {}".format(format_size(source_size)))
    print("Compression format: {}".format(compression_format))
    
    # Set up output
    output_dir = get_output_dir()
    backup_filename = generate_backup_name(source_path, compression_format)
    output_path = os.path.join(output_dir, backup_filename)
    
    # Check if output file already exists
    if os.path.exists(output_path):
        print("Error: Output file already exists: {}".format(output_path))
        sys.exit(1)
    
    print("Output: {}".format(output_path))
    print("")
    print("Starting backup...")
    
    # Create the backup
    format_handlers = {
        'tar.gz': create_tar_gz,
        'tar.bz2': create_tar_bz2,
        'zip': create_zip,
        '7z': create_7z,
    }
    
    handler = format_handlers.get(compression_format)
    if handler is None:
        print("Error: No handler for format '{}'".format(compression_format))
        sys.exit(1)
    
    success = handler(source_path, output_path)
    
    if success:
        if os.path.exists(output_path):
            output_size = os.path.getsize(output_path)
            ratio = (1.0 - float(output_size) / float(source_size)) * 100 if source_size > 0 else 0
            print("")
            print("Backup completed successfully!")
            print("Archive: {}".format(output_path))
            print("Archive size: {}".format(format_size(output_size)))
            print("Compression ratio: {:.1f}% reduction".format(ratio))
        else:
            print("Warning: Handler reported success but output file not found.")
            sys.exit(1)
    else:
        # Clean up partial file on failure
        if os.path.exists(output_path):
            try:
                os.unlink(output_path)
                print("Cleaned up partial archive file.")
            except OSError:
                print("Warning: Could not clean up partial file: {}".format(output_path))
        print("Backup failed!")
        sys.exit(1)


if __name__ == '__main__':
    main()